import React from 'react'

class ProjectRows extends React.Component {

  getLinkOrText(name, link) {
    if (link) {
      return <div><a href={link}>{name}</a></div>
    } else {
      return <div>{name}</div>
    }
  }

  /**
   * Props:
   *   - projectName
   *   - projectLink
   *   - orgName
   *   - orgLink
   *   - orgName2
   *   - orgLink2
   *   - tech
   */
  render() {
    return (<div>
      <div class="row py-1">
        <div class="col">
          {this.getLinkOrText(this.props.projectName, this.props.projectLink)}
          {this.getLinkOrText(this.props.orgName, this.props.orgLink)}
          {this.getLinkOrText(this.props.orgName2, this.props.orgLink2)}
          {this.props.tech && (
            <div>Technologies: {this.props.tech}</div>
          )}
        </div>
      </div>
    </div>)
  }

}

